const jFListTracks = `-- name: JFListTracks :many
SELECT t.id, t.album_id, t.disc_number, t.track_number, t.title, t.duration,
       al.title AS album_title,
       al.slug AS album_slug,
       al.cover_path AS album_cover_path,
       al.genres AS album_genres,
       ar.id AS artist_id,
       ar.name AS artist_name,
       ar.media_item_id AS artist_media_item_id,
       mi.slug AS artist_slug,
       mi.library_id,
       COALESCE((SELECT tf.id FROM track_files tf WHERE tf.track_id = t.id
        ORDER BY tf.quality_score DESC, tf.id ASC LIMIT 1), 0)::bigint AS best_file_id
FROM tracks t
JOIN albums al ON al.id = t.album_id
JOIN artists ar ON ar.id = al.artist_id
JOIN media_items mi ON mi.id = ar.media_item_id
WHERE ($1::bigint = 0 OR t.album_id = $1)
  AND ($2::bigint = 0 OR ar.media_item_id = $2)
  AND ($3::bigint = 0 OR mi.library_id = $3)
  AND (cardinality($4::bigint[]) = 0 OR t.id = ANY($4::bigint[]))
  AND ($5::text = '' OR t.title ILIKE '%' || $5 || '%')
ORDER BY
  CASE WHEN $6::text = 'random' THEN md5(t.id::text || $7::text) END ASC,
  CASE WHEN $6 = 'name' AND $8::bool     THEN lower(t.title) END DESC,
  CASE WHEN $6 = 'name' AND NOT $8::bool THEN lower(t.title) END ASC,
  lower(al.title) ASC, t.disc_number ASC, t.track_number ASC, t.id ASC
LIMIT NULLIF($10::int, 0) OFFSET $9::int
`

